21	const COMPONENT_TYPES = ["rune", "moonstone"];
22	const BLOCK_SIZE = 3;
23	const BLOCK_PRICE = 60;
24	
25	const CURSED_SURCHARGE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const LOYALTY_DISCOUNT = 0.2;
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const FIRST_INSURANCE_SURCHARGE = 0.1;
31	const FOLLOWUP_DISCOUNT = 0.15;
32	
33	const basePriceFor = (type: string): number => BASE_PRICES[type] ?? 0;
34	
35	const isComponentType = (type: string): boolean =>
36	  COMPONENT_TYPES.includes(type);
37	
38	const itemSurchargeRate = (item: Item): number => {
39	  let rate = 0;
40	  if (item.cursed) rate += CURSED_SURCHARGE;
41	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD)
42	    rate += HIGH_ENCHANTMENT_SURCHARGE;
43	  return rate;
44	};
45	
46	const groupByType = (items: Item[]): Map<string, Item[]> =>
47	  items.reduce((groups, item) => {
48	    const group = groups.get(item.type) ?? [];
49	    return groups.set(item.type, [...group, item]);
50	  }, new Map<string, Item[]>());
51	
52	const groupBasePremium = (type: string, group: Item[]): number => {
53	  if (isComponentType(type) && group.length === BLOCK_SIZE) return BLOCK_PRICE;
54	  return group.length * basePriceFor(type);
55	};
56	
57	const groupItemSurcharges = (type: string, group: Item[]): number => {
58	  // Components have no item-specific modifiers.
59	  if (isComponentType(type)) return 0;
60	  const unitBase = basePriceFor(type);
61	  return group.reduce((sum, item) => sum + unitBase * itemSurchargeRate(item), 0);
62	};
